package com.keyloop.scheduler.integration;
import com.keyloop.scheduler.support.*; import org.junit.jupiter.api.*; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.jdbc.core.JdbcTemplate; import static org.assertj.core.api.Assertions.*;
class AppointmentRollbackIT extends PostgresIntegrationTest {@Autowired JdbcTemplate jdbc;@Autowired com.keyloop.scheduler.appointment.application.CreateAppointmentService service;@BeforeEach void seed(){SchedulingFixtures.reset(jdbc);}@Test void failedBookingLeavesNoPartialRows(){var command=new com.keyloop.scheduler.appointment.application.CreateAppointmentCommand(SchedulingFixtures.CUSTOMER,SchedulingFixtures.VEHICLE,SchedulingFixtures.DEALERSHIP,java.util.UUID.randomUUID(),java.time.Instant.parse("2030-01-01T10:00:00Z"),"rollback-001");assertThatThrownBy(()->service.create(command)).isInstanceOf(com.keyloop.scheduler.shared.error.SchedulerException.class);assertThat(jdbc.queryForObject("select count(*) from appointment",Integer.class)).isZero();assertThat(jdbc.queryForObject("select count(*) from appointment_idempotency",Integer.class)).isZero();}}
